CREATE VIEW `dim_sv_epis_di_view` (`epis_id` COMMENT "单集id", `series_id` COMMENT "剧id", `create_time` COMMENT "创建时间", `update_time` COMMENT "修改时间", `create_user` COMMENT "上传人", `cover_url` COMMENT "视频封面", `media_url` COMMENT "媒体播放地址", `file_id` COMMENT "媒体文件的唯一标识", `epis_num` COMMENT "分集序号", `is_free` COMMENT "是否免费", `duration` COMMENT "视频长度", `is_delete` COMMENT "是否删除", `epis_description` COMMENT "分集简介", `file_size` COMMENT "文件大小", `price` COMMENT "分集价格（分）", `publish_status` COMMENT "上架状态", `title` COMMENT "标题", `title_key` COMMENT "标题key", `epis_description_key` COMMENT "分集简介转换key", `stream_url` COMMENT "转码后url", `trans_status` COMMENT "转码状态", `subtitles` COMMENT "字幕文件地址", `series_language` COMMENT "剧语言", `series_name` COMMENT "剧名", `series_last_epis` COMMENT "更新至第几集", `series_all_epis` COMMENT "总集数", `series_ending` COMMENT "完结状态（1连载中 2已完结）")
COMMENT "海剧分集信息表" AS SELECT `ods`.`a`.`EpisId` AS `epis_id`, `ods`.`a`.`SeriesId` AS `series_id`, `ods`.`a`.`CreateTime` AS `create_time`, `ods`.`a`.`UpdateTime` AS `update_time`, `ods`.`a`.`CreateUser` AS `create_user`, `ods`.`a`.`CoverUrl` AS `cover_url`, `ods`.`a`.`MediaUrl` AS `media_url`, `ods`.`a`.`FileId` AS `file_id`, `ods`.`a`.`EpisNum` AS `epis_num`, `ods`.`a`.`IsFree` AS `is_free`, `ods`.`a`.`duration`, `ods`.`a`.`IsDelete` AS `is_delete`, `ods`.`a`.`EpisDescription` AS `epis_description`, `ods`.`a`.`FileSize` AS `file_size`, `ods`.`a`.`price`, `ods`.`a`.`PublishStatus` AS `publish_status`, `ods`.`a`.`title`, `ods`.`a`.`TitleKey` AS `title_key`, `ods`.`a`.`episdescriptionkey` AS `epis_description_key`, `ods`.`a`.`streamurl` AS `stream_url`, `ods`.`a`.`transstatus` AS `trans_status`, `ods`.`a`.`subtitles`, `ods`.`b`.`language` AS `series_language`, `ods`.`b`.`SeriesName` AS `series_name`, `ods`.`b`.`LastEpis` AS `series_last_epis`, `ods`.`b`.`AllEpis` AS `series_all_epis`, `ods`.`b`.`Ending` AS `series_ending`
FROM `ods`.`ods_tidb_short_video_epis` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_short_video_series` AS `b` ON `ods`.`a`.`SeriesId` = `ods`.`b`.`SeriesId`;
